export interface PumpShift {
  id: number;
  clientId: number;
  /**
     * Multi-station (P8): station this shift belongs to, denormalized from the pump at creation time.
     * @nullable
     */
  stationId?: number | null;
  /**
     * Display name of the station, for filtering and reporting.
     * @nullable
     */
  stationName?: string | null;
  /** @nullable */
  cashRegisterId?: number | null;
  pumpLabel: string;
  fuelType: FuelType;
  indexStart: number;
  indexEnd: number;
  /** Computed as indexEnd - indexStart. */
  volumeLiters: number;
  status: PumpShiftStatus;
  /**
     * FCFA price per litre applied at validation, resolved server-side from the client's active FuelPrice for this fuel type.
     * @nullable
     */
  unitPrice?: number | null;
  paymentMethod?: PaymentMethod | null;
  /**
     * unitPrice x volumeLiters, rounded to the nearest FCFA.
     * @nullable
     */
  expectedAmount?: number | null;
  /** @nullable */
  declaredPhysicalAmount?: number | null;
  /** @nullable */
  discrepancyAmount?: number | null;
  /**
     * FCFA collected in cash (Espèces) for this shift. Null for shifts created before the split-payment upgrade.
     * @nullable
     */
  cashAmount?: number | null;
  /**
     * FCFA collected via Wave (552200).
     * @nullable
     */
  waveAmount?: number | null;
  /**
     * FCFA collected via Orange Money (552100).
     * @nullable
     */
  orangeMoneyAmount?: number | null;
  /**
     * FCFA collected via MTN MoMo (552300).
     * @nullable
     */
  mtnMomoAmount?: number | null;
  /** @nullable */
  transactionId?: number | null;
  /** @nullable */
  discrepancyTransactionId?: number | null;
  /** @nullable */
  openedByName?: string | null;
  /** @nullable */
  validatedByName?: string | null;
  /** @nullable */
  validatedAt?: string | null;
  createdAt: string;
}

export interface PumpShiftCreateInput {
  clientId: number;
  /** @minLength 1 */
  pumpLabel: string;
  fuelType: FuelType;
  /** @minimum 0 */
  indexEnd: number;
}

export interface PumpShiftValidateInput {
  /**
     * FCFA collected in cash (Espèces). Maps to the pompiste's personal 5711xx sub-account. The sum cashAmount + waveAmount + orangeMoneyAmount + mtnMomoAmount must equal the computed expectedAmount.
     * @minimum 0
     */
  cashAmount?: number;
  /**
     * FCFA collected via Wave. Maps to account 552200.
     * @minimum 0
     */
  waveAmount?: number;
  /**
     * FCFA collected via Orange Money. Maps to account 552100.
     * @minimum 0
     */
  orangeMoneyAmount?: number;
  /**
     * FCFA collected via MTN MoMo. Maps to account 552300.
     * @minimum 0
     */
  mtnMomoAmount?: number;
  /**
     * Required when cashAmount > 0 -- the cash physically counted for this shift (used to compute the écart de caisse against the cashAmount).
     * @nullable
     */
  declaredPhysicalAmount?: number | null;
}

export interface PumpShiftValidateResult {
  pumpShift: PumpShift;
  saleTransaction: TransactionDetail;
  discrepancyTransaction?: TransactionDetail | null;
}

